def predict_next_frame(frame, action, xy=None):
    # Create a deep copy of the frame to avoid modifying the original
    next_frame = [row[:] for row in frame]

    if action == "ACTION5":
        # ACTION5 changes cells from color 2 to color 3
        # Based on the examples, it seems to change all cells with value 2 to value 3
        for i in range(64):
            for j in range(64):
                if next_frame[i][j] == 2:
                    next_frame[i][j] = 3
    elif action == "ACTION6":
        # ACTION6 is a click at coordinates (x, y)
        # For this specific game, it seems to change the clicked cell and its neighbors
        # from color 4 to color 5, but only if they are currently color 4
        if xy is not None:
            x, y = xy
            # Check bounds
            if 0 <= x < 64 and 0 <= y < 64:
                # Change the clicked cell and its 8 neighbors if they are color 4
                for dx in [-1, 0, 1]:
                    for dy in [-1, 0, 1]:
                        nx, ny = x + dx, y + dy
                        if 0 <= nx < 64 and 0 <= ny < 64:
                            if next_frame[ny][nx] == 4:
                                next_frame[ny][nx] = 5

    # For other actions, return the frame unchanged
    return next_frame

